// Inputs on incoming item:
//   "Chunk Path"   -> base URL ending in "chunk_" (e.g. .../chunks/chunk_)
//   "Chunk Amount" -> number of chunks (e.g. 8)

const CHUNK_START_INDEX = 1; // set to 0 if your chunks are 0-indexed

const item = $input.first().json;

const chunkPath = item['Chunk Path'];
const chunkAmount = Number(item['Chunk Amount']);

if (!chunkPath) {
  throw new Error('Missing "Chunk Path" input.');
}
if (!chunkAmount || chunkAmount < 1) {
  throw new Error('"Chunk Amount" must be a number >= 1.');
}

const video_urls = [];
for (let i = CHUNK_START_INDEX; i < CHUNK_START_INDEX + chunkAmount; i++) {
  video_urls.push({ video_url: `${chunkPath}${i}.mp4` });
}

const payload = {
  video_urls,
  id: `concat_${Date.now()}`
};

return [{ json: payload }];

